                              stopLoop = true


                              var teamString = team.assigned_ho[index2].team
                              var teamString = teamString.substring(teamString.indexOf("(")+1,teamString.indexOf(")"))


                              content.push(<div style={{fontSize: "14px", marginTop: "35px", marginLeft: "20px", marginBottom: "10px"}}>Meet {teamString.replace("Medicine","").replace("Night","").replace("Attending","").replace("(","").replace(")","").replace("Resident","").replace("1","").replace("2","").replace("4","").replace("Swing","").replace("Shift","").trim()}  at {findSignoutTime} for sign out in your team room <br></br></div>)


                              findSignoutTime = d.toLocaleString([], {hour: '2-digit', minute: '2-digit'})
                            }
                            counter += 1
                        }



                    }
                    var ho = team.assigned_ho[index2]

                    var covidString = <font style={{color: "red", fontSize: "14px"}}><i></i></font>
                    if (ho.COVID.length > 0) {
                        covidString = <font style={{color: "red", fontSize: "14px"}}><br></br><i>*** {ho.COVID}</i></font>
                    }
                    var teamName = ""
                    teamName = "Sign out from " + ho.team
                    if (ho.team === "Medicine X Robin") {
                        teamName = "**CrossCover signout from Eagle; Detailed sign out from Medicine X Robin"
                    }

                    var remainLocation = ""
                    try {
                        if (ho.Location.length > 0) {
                            remainLocation = " (" + ho.Location + ")"
                        } 
                    } catch (e) {}
                    content.push(<div style={{fontSize: "14px", marginTop: "35px", marginLeft: "20px", marginBottom: "10px"}}><font style={{color: "#8B4513"}}><b>MRN: {ho.MRN} - {ho.Name} {remainLocation}</b></font><font style={{color: "#9B870C", fontSize: "14px"}}> - <u>{teamName}</u></font><div>{covidString}</div><div style={{marginTop: "10px"}}><font style={{color: 'blue'}}>{ho.OneLiner ? ho.OneLiner : ""}</font></div></div>)

                }



            }


            content.push(<div style={{marginTop: paragraphSpace}}>Total # of holdovers = {this.state.result.totalHO}</div>)

            content.push(<div style={{marginTop: paragraphSpace}}>Total # of swing admits = ***</div>)
            content.push(<div style={{marginTop: singleSpace}}>Koala:</div>)
            content.push(<div style={{marginTop: singleSpace}}>Toucan:</div>)
            content.push(<div style={{marginTop: singleSpace}}>Sparrow:</div>)
            content.push(<div style={{marginTop: singleSpace}}>Swing retainer (Robin):</div>)


            content.push(<div style={{marginTop: paragraphSpace}}>Total # of night admits</div>)
            content.push(<div style={{marginTop: singleSpace}}>Badger:</div>)
            content.push(<div style={{marginTop: singleSpace}}>Wolf:</div>)
            content.push(<div style={{marginTop: singleSpace}}>Hawk:</div>)
            content.push(<div style={{marginTop: singleSpace}}>Owl:</div>)
            content.push(<div style={{marginTop: singleSpace}}>Quail:</div>)
            content.push(<div style={{marginTop: singleSpace}}>Eagle:</div>)


            //content.push(<div style={{marginTop: paragraphSpace}}>Total # of re-triaged patients</div>)
            //content.push(<div style={{marginTop: singleSpace}}>Mt Zion:</div>)
            //content.push(<div style={{marginTop: singleSpace}}>St. Mary's:</div>)

            content.push(<div style={{marginTop: paragraphSpace}}>Total # admits by jeopardy/other (please specify) = ***</div>)


            //content.push(<div style={{marginTop: doubleSpace}}><img src={footer}/></div>)
            content.push(<div style={{marginTop: doubleSpace}}><img src="https://applet.ucsf.edu/media/footer.png" width="800px"></img></div>)



            content.push(<div style={{marginBottom: "50px"}}>&nbsp;</div>)
        }



        return (
            <div style={{minHeight: "500px", marginLeft: "50px", marginRight: "50px"}}><h2 className="display-4 text-center">{header}</h2>{content}
            </div>
        );


      }


}


export default CyberRaptorV2
